        switch (extension) {
            case "jpg":
            case "jpeg":
                return ImageType.JPG;
            case "png":
                return ImageType.PNG;
            case "svg":
                return ImageType.SVG;
            case "tif":
            case "tiff":
                return ImageType.TIFF;
            case "psd":
