                        "\t\t\t\"idiom\": \"universal\",\n" +
                        "\t\t\t\"scale\": \"" + densityDescription.name + "\"\n" +
                        "\t\t},");
            }
        }
        sb.setLength(sb.length() - 1);
        sb.append("\n\t],\n\t\"info\": {\n\t\t\"author\": \"xcode\",\n\t\t\"version\": 1\n\t}\n}");

        return sb.toString();
    }

